// Custom ObjectInputStream that restricts which classes can be deserialized
class SafeObjectInputStream(inputStream: InputStream, allowedClasses: Set[String])
    extends ObjectInputStream(inputStream) {

  override def resolveClass(desc: ObjectStreamClass): Class[_] = {
    val className = desc.getName

    // Allow primitive types and basic Java types needed for deserialization
    val alwaysAllowed = Set(
      "java.lang.String",
      "java.lang.Long",
      "java.lang.Integer",
      "java.lang.Number",
      "[B", // byte array
      "[C", // char array
    )

    if (alwaysAllowed.contains(className) || allowedClasses.contains(className)) {
      super.resolveClass(desc)
    } else {
      throw new InvalidClassException(
        className,
        s"Deserialization of class '$className' is not allowed. " +
          s"Only whitelisted classes may be deserialized."
      )
    }
  }
}

// Actor that processes only safe, validated messages
