// Network listener that accepts connections and safely deserializes messages
class NetworkMessageListener(
    port: Int,
    system: ActorSystem,
    processorActor: akka.actor.ActorRef
) {

  private val executor = Executors.newCachedThreadPool()
  implicit private val ec: ExecutionContext = ExecutionContext.fromExecutor(executor)

  @volatile private var running = true
  private var serverSocket: ServerSocket = _

  def start(): Unit = {
    Future {
      serverSocket = new ServerSocket(port)
      system.log.info(s"Network listener started on port $port")

      while (running) {
        try {
          val socket = serverSocket.accept()
          handleConnection(socket)
        } catch {
          case _: java.net.SocketException if !running =>
            system.log.info("Server socket closed, shutting down listener")
          case e: Exception =>
            system.log.error(e, "Error accepting connection")
        }
      }
    }
  }

  private def handleConnection(socket: Socket): Unit = {
    Future {
      try {
        // Set a read timeout to prevent slow-loris attacks
        socket.setSoTimeout(5000)

        val inputStream = socket.getInputStream
        val dis = new DataInputStream(inputStream)

        try {
          // Read length-prefixed message
          val length = dis.readInt()

          if (length <= 0 || length > SafeDeserializer.maxPayloadSize) {
            system.log.warning(s"Invalid message length: $length from ${socket.getRemoteSocketAddress}")
            return
          }

          val data = new Array[Byte](length)
          dis.readFully(data)

          // Use safe deserialization with whitelist
          SafeDeserializer.deserialize(data) match {
            case Right(message) =>
              system.log.info(s"Successfully deserialized message from ${socket.getRemoteSocketAddress}")
              processorActor ! message

            case Left(error) =>
              system.log.warning(
                s"Rejected message from ${socket.getRemoteSocketAddress}: $error"
              )
          }
        } finally {
          dis.close()
        }
      } catch {
        case e: java.net.SocketTimeoutException =>
          system.log.warning(s"Connection timeout from ${socket.getRemoteSocketAddress}")
        case e: EOFException =>
          system.log.warning(s"Unexpected end of stream from ${socket.getRemoteSocketAddress}")
        case e: Exception =>
          system.log.error(e, s"Error handling connection from ${socket.getRemoteSocketAddress}")
      } finally {
        try { socket.close() } catch { case _: Exception => }
      }
    }
  }

  def stop(): Unit = {
    running = false
    if (serverSocket != null && !serverSocket.isClosed) {
      serverSocket.close()
    }
    executor.shutdown()
  }

  // Expose max payload size for reference
  private[this] val maxPayloadSize: Int = 64 * 1024
}

